class Solution:
    def countVisiblePeople(self, n, pos, k):
        MOD = 1000000007
        left = pos
        right = n - 1 - pos
        top = max(left, right, k, 1)
        fact = [1] * (top + 1)
        for i in range(1, top + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (top + 1)
        inv_fact[top] = pow(fact[top], MOD - 2, MOD)
        for i in range(top, 0, -1):
            inv_fact[i - 1] = inv_fact[i] * i % MOD
        def C(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] * inv_fact[b] % MOD * inv_fact[a - b] % MOD
        # Directly sum every left/right split, without relying on Vandermonde's identity.
        total = 0
        for m in range(0, min(k, left) + 1):
            j = k - m
            total = (total + C(left, m) * C(right, j)) % MOD
        return (2 * total) % MOD

