        if k < 0 or k > m:
            return 0
        fact = [1] * (m + 1)
        for i in range(1, m + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (m + 1)
        inv_fact[m] = pow(fact[m], MOD - 2, MOD)
        for i in range(m, 0, -1):
            inv_fact[i - 1] = inv_fact[i] * i % MOD
        c = fact[m] * inv_fact[k] % MOD * inv_fact[m - k] % MOD
        return (2 * c) % MOD

