var countVisiblePeople = function(n, pos, k) {
    const MOD = 1000000007n;
    const m = n - 1;
    if (k < 0 || k > m) return 0;
    const fact = new Array(m + 1);
    fact[0] = 1n;
    for (let i = 1; i <= m; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    function modpow(base, exp, mod) {
        base %= mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }
    const invFact = new Array(m + 1);
    invFact[m] = modpow(fact[m], MOD - 2n, MOD);
    for (let i = m; i >= 1; i--) invFact[i - 1] = (invFact[i] * BigInt(i)) % MOD;
    const c = (fact[m] * invFact[k] % MOD) * invFact[m - k] % MOD;
    return Number((2n * c) % MOD);
};
